<script lang="ts">
  /**
   * Signup page -- invite-code-based onboarding.
   *
   * Two modes (driven by +page.server.ts):
   *   • First-user (no users in DB): becomes the OWNER. Name + email
   *     + passkey enrollment -- no invite code required.
   *   • Invite-required: 6-digit invite code (generated by an existing
   *     owner) + name + email + passkey. We POST the code to
   *     /api/auth/invite/claim before the WebAuthn ceremony so the user
   *     doesn't get a half-baked account if the code is invalid.
   *
   * Design: mirrors the login page (hero brand mark, gradient bloom bg,
   * glassy card, h-12 primary action) plus a top-left chevron-back link
   * to /login so users who tapped "Set up with invite code" by mistake
   * have an obvious escape hatch. Better Auth's passkey plugin handles
   * the actual WebAuthn ceremony; on success we redirect to /onboarding.
   */
  import { authClient, setPendingInviteCode } from '$lib/client/auth-client';
  import { Button } from '$lib/components/ui/button';
  import { Input } from '$lib/components/ui/input';
  import { Label } from '$lib/components/ui/label';
  import { KeyRound, AlertCircle, ChevronLeft, ShieldCheck } from '@lucide/svelte';
  import { goto } from '$app/navigation';
  import { APP_NAME } from '$lib/config/branding';
  // Smooth height animation when the error banner mounts/unmounts --
  // see /login for rationale.
  import { slide } from 'svelte/transition';
  import { cubicOut } from 'svelte/easing';

  let { data } = $props<{
    data: { isFirstUser: boolean; githubEnabled: boolean };
  }>();

  let name = $state('');
  let email = $state('');
  let inviteCode = $state('');
  let busy = $state(false);
  let error = $state<string | null>(null);

  /**
   * Translate raw signup / WebAuthn / API errors into friendly copy.
   * Mirrors the login page's friendlyAuthError() helper so the auth
   * surface is consistent across both screens.
   */
  function friendlyError(raw: unknown, fallback = 'Account creation failed.'): string {
    const msg =
      raw instanceof Error
        ? raw.message
        : typeof raw === 'string'
          ? raw
          : raw && typeof raw === 'object' && 'message' in raw
            ? String((raw as { message: unknown }).message ?? '')
            : '';
    const lower = msg.toLowerCase();

    if (
      lower.includes('cancel') ||
      lower.includes('aborted') ||
      lower.includes('notallowed') ||
      lower.includes('not allowed') ||
      lower.includes('timed out') ||
      lower.includes('timeout')
    ) {
      return "Passkey setup was cancelled. Tap Create again when you're ready — your device prompt should appear.";
    }
    if (lower.includes('not supported') || lower.includes('unsupported')) {
      return 'Passkeys are not supported on this device. Try Safari (iOS) or a recent Chrome / Firefox.';
    }
    if (lower.includes('network') || lower.includes('fetch')) {
      return "Couldn't reach the sign-up server. Check your connection and try again.";
    }
    if (lower.includes('invite') && lower.includes('used')) {
      return 'That invite code has already been used. Ask the owner to issue a new one.';
    }
    if (lower.includes('invite') && (lower.includes('invalid') || lower.includes('not found'))) {
      return "We couldn't find that invite code. Double-check the digits with whoever invited you.";
    }
    if (lower.includes('email') && lower.includes('exist')) {
      return 'An account with that email already exists. Sign in instead?';
    }
    if (!msg) return fallback;
    return msg;
  }

  async function createAccount() {
    // Don't clear `error = null` here -- see /login's signInWithPasskey
    // for the rationale. Clearing it causes the inline error banner to
    // unmount and remount on each click, jumping the layout. Cleared
    // only on the SUCCESS path (after the goto to /onboarding).
    if (!name.trim()) {
      error = 'Please enter your name.';
      return;
    }
    if (!email.trim() || !email.includes('@')) {
      error = 'Please enter a valid email address.';
      return;
    }
    if (!data.isFirstUser && !/^\d{6}$/.test(inviteCode.trim())) {
      error = 'Invite code must be 6 digits.';
      return;
    }

    busy = true;
    try {
      // For non-first users, validate the invite code first so we don't
      // create a half-baked account before realising the code is bad.
      // This is the UX check; the SERVER also enforces single-use
      // redemption in hooks.server.ts's signupGate, so even if the user
      // somehow skips this validation the actual signup POST will be
      // rejected without a valid header.
      if (!data.isFirstUser) {
        const claim = await fetch('/api/auth/invite/claim', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ code: inviteCode.trim(), email: email.trim() }),
        });
        if (!claim.ok) {
          const body = await claim.json().catch(() => null);
          error = friendlyError(body?.error?.message, 'Invite code not accepted.');
          busy = false;
          return;
        }
        // Stash the code so customFetch attaches it as `x-invite-code`
        // on the immediately-following authClient.signUp.email call.
        // The slot is single-use (cleared after attach) so a stale
        // code can never leak into an unrelated request.
        setPendingInviteCode(inviteCode.trim());
      }

      // Create the account via passkey. Better Auth's plugin will:
      //   1. Generate WebAuthn options
      //   2. Trigger the browser's passkey UI
      //   3. Persist the new user + credential
      //   4. Set the session cookie
      const result = await authClient.signUp.email({
        email: email.trim(),
        password: crypto.randomUUID(), // unused -- emailAndPassword is disabled
        name: name.trim(),
      });

      if (result?.error) {
        error = friendlyError(result.error);
        busy = false;
        return;
      }

      // Immediately enroll a passkey for the new account.
      const pk = await authClient.passkey.addPasskey({
        name: name.trim() + "'s passkey",
      });
      if (pk?.error) {
        error = friendlyError(pk.error, 'Account created, but passkey setup failed.');
        busy = false;
        return;
      }

      // Success path -- clear any stale error before navigating away.
      error = null;
      await goto('/onboarding', { invalidateAll: true });
    } catch (e) {
      error = friendlyError(e);
      busy = false;
    }
  }
</script>

<svelte:head>
  <title>Set up account — {APP_NAME}</title>
</svelte:head>

<main
  class="relative flex min-h-svh flex-col items-center justify-center overflow-hidden bg-background px-6 py-12"
>
  <!-- Dawn-sky bloom backdrop. SINGLE SOURCE: scripts/native/splash-spec.mjs
       (bloomCssInline) via apply-brand -- shared with /login + the boot +
       splash screens so the whole entry flow is one continuous surface.
       Regenerate with `pnpm brand:apply`; do NOT hand-edit between markers. -->
  <!-- AUTO-GENERATED:splash-bloom -->
  <div
    aria-hidden="true"
    class="pointer-events-none absolute inset-0 overflow-hidden"
    style="background: radial-gradient(135% 100% at 50% 50%, transparent 46%, rgba(0, 0, 0, 0.42) 100%), radial-gradient(120% 85% at 50% 116%, rgba(200, 155, 74, 0.34) 0%, rgba(200, 155, 74, 0.12) 30%, transparent 58%), radial-gradient(135% 95% at 50% 104%, rgba(122, 140, 109, 0.2) 0%, transparent 62%), radial-gradient(80% 62% at 50% 40%, rgba(74, 91, 109, 0.26) 0%, rgba(122, 140, 109, 0.1) 46%, transparent 74%), linear-gradient(180deg, #090b0f 0%, #0e1014 44%, #11151c 100%);"
  ></div>
  <!-- /AUTO-GENERATED:splash-bloom -->

  <!-- Top-left BACK button — escape hatch back to /login. Always shown:
       /login is the universal entry now (it renders the login screen with a
       "Set up with invite code" link rather than bouncing zero-user installs
       back to /signup), so Back is never a dead-end even for the first user. -->
  <a
    href="/login"
    aria-label="Back to sign in"
    class="absolute left-[max(0.5rem,env(safe-area-inset-left))] top-[max(0.5rem,env(safe-area-inset-top))] z-20 inline-flex h-9 items-center gap-1 rounded-full px-3 text-sm font-medium text-muted-foreground transition-colors hover:bg-muted/40 hover:text-foreground"
  >
    <ChevronLeft class="size-4" />
    Back
  </a>

  <div class="relative z-10 flex w-full max-w-sm flex-col items-center">
    <!-- Brand mark hero — same SVG composition as /login so the brand
         identity reads continuously across the auth flow. -->
    <div
      class="mb-7 flex size-16 items-center justify-center"
      style="filter: drop-shadow(0 6px 24px rgba(122, 140, 109, 0.35)) drop-shadow(0 1px 2px rgba(0, 0, 0, 0.25));"
      aria-hidden="true"
    >
      <svg width="64" height="64" viewBox="0 0 1024 1024">
        <!-- AUTO-GENERATED:brand-mark gradient-id="signup-bg" -->
        <image
          width="1024"
          height="1024"
          preserveAspectRatio="xMidYMid meet"
          href="data:image/webp;base64,"
        />
        <!-- /AUTO-GENERATED:brand-mark -->
      </svg>
    </div>

    <h1 class="text-center text-3xl font-semibold tracking-tight">
      {data.isFirstUser ? `Welcome to ${APP_NAME}` : 'Set up your account'}
    </h1>
    <p class="mt-2 text-center text-sm text-muted-foreground">
      {#if data.isFirstUser}
        The first account becomes the workspace owner. You can invite others later from Settings.
      {:else}
        Use your invite code to claim a seat. You'll set up a passkey so sign-in is instant next
        time.
      {/if}
    </p>

    {#if error}
      <!--
        Inline icon with `vertical-align: middle` rather than flex +
        wrapper math — see /login for the full rationale. The icon's
        vertical position tracks the text's x-height center
        naturally, no magic margins.
      -->
      <div
        class="mt-6 w-full overflow-hidden rounded-lg border border-red-500/30 bg-red-500/10 p-3 text-sm text-red-700 dark:text-red-200"
        role="alert"
        transition:slide={{ duration: 220, easing: cubicOut }}
      >
        <p class="leading-relaxed">
          <AlertCircle class="mr-2 inline-block size-4 align-middle" />
          {error}
        </p>
      </div>
    {/if}

    <!-- Card wrapping the form. Same glassy aesthetic as /login so the
         user feels like they're filling out a form inside the same
         surface, not arriving at a totally new screen. -->
    <form
      class="mt-6 w-full rounded-2xl border border-border/40 bg-card/60 p-5 shadow-2xl backdrop-blur-xl"
      onsubmit={(e) => {
        e.preventDefault();
        createAccount();
      }}
    >
      <div class="grid gap-4">
        {#if !data.isFirstUser}
          <div class="grid gap-1.5">
            <Label for="invite" class="text-xs uppercase tracking-wide text-muted-foreground"
              >Invite code</Label
            >
            <!--
              `pattern={'\\d{6}'}` is wrapped in a JS string expression
              because Svelte parses `{...}` inside attribute values as a
              JS expression — the bare HTML5 pattern `\d{6}` would
              interpolate `{6}` to the number 6, emitting the broken
              attribute `pattern="\d6"` that rejects every input
              including the legitimate 6-digit code.
            -->
            <Input
              id="invite"
              bind:value={inviteCode}
              maxlength={6}
              inputmode="numeric"
              pattern={'\\d{6}'}
              placeholder="123456"
              autocomplete="one-time-code"
              disabled={busy}
              class="h-12 text-center font-mono text-lg tracking-[0.5em]"
            />
          </div>
        {/if}

        <div class="grid gap-1.5">
          <Label for="name" class="text-xs uppercase tracking-wide text-muted-foreground"
            >Name</Label
          >
          <Input
            id="name"
            bind:value={name}
            placeholder="Alice Johnson"
            autocomplete="name"
            disabled={busy}
            class="h-12"
          />
        </div>

        <div class="grid gap-1.5">
          <Label for="email" class="text-xs uppercase tracking-wide text-muted-foreground"
            >Email</Label
          >
          <Input
            id="email"
            type="email"
            bind:value={email}
            placeholder="you@example.com"
            autocomplete="email"
            disabled={busy}
            class="h-12"
          />
        </div>

        <Button
          type="submit"
          disabled={busy}
          class="mt-2 h-12 w-full justify-center gap-2 bg-gradient-to-r from-indigo-500 via-violet-500 to-fuchsia-500 font-medium text-white shadow-lg shadow-violet-500/25 transition-all hover:shadow-violet-500/40 disabled:opacity-60"
        >
          <KeyRound class="size-4" />
          {busy ? 'Setting up…' : 'Create account & set up passkey'}
        </Button>
      </div>
    </form>

    <!-- Trust reassurance — matches /login. Describes the actual
         security model (passkey private key never leaves the device)
         instead of using "end-to-end" jargon. -->
    <div
      class="mt-6 flex items-center gap-2 rounded-full bg-emerald-500/8 px-3 py-1.5 text-[11px] text-emerald-800 dark:text-emerald-300/80"
    >
      <ShieldCheck class="size-3.5" />
      <span>Private by design · Your device is the key</span>
    </div>

    <!-- Secondary navigation: already-have-account link sits at the
         bottom so it doesn't compete with the primary action above.
         HIDDEN in first-user mode — by definition NO account exists
         yet, so prompting "Already have an account? Sign in" is
         nonsensical and would just dump the user back at /signup. -->
    {#if !data.isFirstUser}
      <p class="mt-6 text-xs text-muted-foreground">
        Already have an account?
        <a href="/login" class="text-foreground underline-offset-4 hover:underline">Sign in</a>
      </p>
    {/if}
  </div>
</main>
